import{_ as e,o,c as l,ag as a}from"./chunks/framework.BZohXCq9.js";const i="/pettheccb.gif",s="/streamerBot.png",b=JSON.parse('{"title":"🤖 What is CoolClubBot? 🤖","description":"","frontmatter":{"outline":false},"headers":[],"relativePath":"pages/coolclubbot.md","filePath":"pages/coolclubbot.md","lastUpdated":1773600249000}'),r={name:"pages/coolclubbot.md"};function n(c,t,h,d,m,u){return o(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="🤖-what-is-coolclubbot-🤖" tabindex="-1">🤖 What is CoolClubBot? 🤖 <a class="header-anchor" href="#🤖-what-is-coolclubbot-🤖" aria-label="Permalink to &quot;🤖 What is CoolClubBot? 🤖&quot;">​</a></h1><hr><h3 id="welcome-to-my-brainchild" tabindex="-1">Welcome to my brainchild! <a class="header-anchor" href="#welcome-to-my-brainchild" aria-label="Permalink to &quot;Welcome to my brainchild!&quot;">​</a></h3><p>I made a basic Discord Bot for my community Discord server using discord.js! Thanks to Under Ctrl, MrJAwesome, and others for the basic tutorials</p><blockquote><p>CoolClubBot, or just CCB for short, is a Discord bot built by myself from the ground-up with javascript. Not to be confused with the CoolClubBot Twitch chatbot, which works via Streamer.bot, CCB can do anything I want it to do from welcoming new members to saving users&#39; birthdays, all personalized for our community! You can find CoolClubBot&#39;s public repository <a href="https://github.com/CoolAid48/CoolClubBot" target="_blank" rel="noreferrer">here on GitHub</a>.</p></blockquote><h2 id="here-s-a-complete-list-of-all-coolclubbot-s-features-and-commands" tabindex="-1">Here&#39;s a complete list of all CoolClubBot&#39;s features and commands! <a class="header-anchor" href="#here-s-a-complete-list-of-all-coolclubbot-s-features-and-commands" aria-label="Permalink to &quot;Here&#39;s a complete list of all CoolClubBot&#39;s features and commands!&quot;">​</a></h2><ul><li><p>Welcoming system where new members will be welcomed by the bot in the #welcomes channel upon joining the server.</p></li><li><p>Randomized status of 4 options for the bot on a 60-second interval for some &quot;personality&quot;.</p></li><li><p>Simple message command where typing &quot;hello&quot; will prompt the bot to respond with a little message!</p></li><li><p>Autorole logic for users to get a temporary &quot;LIVE NOW&quot; role and get displayed towards the top of the members list (free self-promo) when streaming on Twitch</p></li><li><p>&quot;Starboard&quot; system where highly reacted messages will get &quot;pinned&quot; in an embed format in the #collard-board channel for all to see. We call this the collard board.</p></li><li><p>Various prefix commands using the (!) prefix for CCB to respond to. Full list of commands and their uses below!</p></li></ul><div style="display:flex;justify-content:flex-start;align-items:flex-start;flex-wrap:wrap;"><div style="flex:1 0 500px;"><ul><li>!hofapp: Replies with Hall of Fame info</li><li>!modrinth: Replies with a link to Modrinth</li><li>!mods: Replies with a link to Coolaid&#39;s mods list</li><li>!ping: Replies with &quot;Pong!&quot; and the bot&#39;s ping</li><li>!rules: Replies with a reminder to check out the rules channel</li><li>!specs: Replies with a link to Coolaid&#39;s setup and specs list</li><li>!support: Replies with a link to the ticket channel for support</li><li>!rules: Replies with a reminder to check out the rules channel</li></ul></div><div style="flex:0 0 auto;"><img src="'+i+'" alt="PETTHECCB" width="180"></div></div><table tabindex="0"><thead><tr><th style="text-align:center;">🤖 You&#39;ll also see CoolClubBot in Twitch chat! 🤖</th></tr></thead><tbody><tr><td style="text-align:center;">CoolClubBot is also a Twitch chatbot, works via <a href="https://streamer.bot/" target="_blank" rel="noreferrer">Streamer.bot</a> and can do everything (and more)</td></tr><tr><td style="text-align:center;"><img src="'+s+'" alt="streamer.bot" width="800"></td></tr></tbody></table>',9)])])}const f=e(r,[["render",n]]);export{b as __pageData,f as default};
